document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".instructor-profile-img").forEach(t=>{t.addEventListener("error",function(){this.dataset.fallbackSrc&&this.src!==this.dataset.fallbackSrc&&(this.src=this.dataset.fallbackSrc)})}),document.querySelectorAll(".instructor-delete-form").forEach(t=>{t.addEventListener("submit",function(t){if(!confirm("Are you sure you want to delete this instructor?"))return t.preventDefault(),!1})})});